import React, { useState } from "react";
import axios from "axios";

function App() {

  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");

  const sendMessage = async () => {

    if (!input.trim()) return;

    const userMessage = {
      role: "user",
      text: input
    };

    setMessages(prev => [...prev, userMessage]);

    const res = await axios.post(
    "http://localhost:5001/chat",
      { message: input }
    );

    const aiMessage = {
      role: "ai",
      text: res.data.reply
    };

    setMessages(prev => [...prev, aiMessage]);

    setInput("");
  };

  return (

    <div style={styles.container}>

      <div style={styles.chatBox}>

        <h2 style={styles.title}>AI Chatbot</h2>

        <div style={styles.messages}>

          {messages.map((msg, index) => (

            <div
              key={index}
              style={
                msg.role === "user"
                  ? styles.userMessage
                  : styles.aiMessage
              }
            >
              {msg.text}
            </div>

          ))}

        </div>

        <div style={styles.inputArea}>

          <input
            style={styles.input}
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder="Ask something..."
          />

          <button
            style={styles.button}
            onClick={sendMessage}
          >
            Send
          </button>

        </div>

      </div>

    </div>

  );
}

const styles = {

  container: {
    height: "100vh",
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    backgroundColor: "#f0f2f5",
    fontFamily: "Arial"
  },

  chatBox: {
    width: "500px",
    height: "600px",
    background: "white",
    borderRadius: "10px",
    display: "flex",
    flexDirection: "column",
    boxShadow: "0 5px 15px rgba(0,0,0,0.2)"
  },

  title: {
    textAlign: "center",
    padding: "15px",
    borderBottom: "1px solid #ddd"
  },

  messages: {
    flex: 1,
    padding: "15px",
    overflowY: "auto",
    display: "flex",
    flexDirection: "column",
    gap: "10px"
  },

  userMessage: {
    alignSelf: "flex-end",
    background: "#007bff",
    color: "white",
    padding: "10px 15px",
    borderRadius: "15px",
    maxWidth: "70%"
  },

  aiMessage: {
    alignSelf: "flex-start",
    background: "#e4e6eb",
    padding: "10px 15px",
    borderRadius: "15px",
    maxWidth: "70%"
  },

  inputArea: {
    display: "flex",
    padding: "10px",
    borderTop: "1px solid #ddd"
  },

  input: {
    flex: 1,
    padding: "10px",
    borderRadius: "8px",
    border: "1px solid #ccc"
  },

  button: {
    marginLeft: "10px",
    padding: "10px 15px",
    background: "#007bff",
    color: "white",
    border: "none",
    borderRadius: "8px",
    cursor: "pointer"
  }

};

export default App;
